var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"버넷 씨! 좀 더 고상한 포즈로 부탁드릴게요!","JPN":"バーネットさん！　もう少し高尚なポーズでお願いします！","ENG":"Mr. Burnett! Could you do a more elegant pose, please?","TWN":"伯內特！請擺一個再優雅一點的姿勢！"},"stage":{"bg":"STORE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"뤼미에르 부티크의 브랜드 이미지에 걸맞은 고풍스러운 이미지를 보여주세요!","JPN":"ルミエールブティックのブランドイメージにふさわしい、古風な感じでお願いします！","ENG":"Show us a sophisticated image that can represent the Lumiere Boutique brand!","TWN":"請表現出符合精品店的奢華形象！"},"stage":{"bg":"STORE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 귀찮아 죽겠네.","JPN":"ったく、めんどくせえな。","ENG":"Agh, bollocks. So annoying.","TWN":"受不了，麻煩死了。"},"stage":{"bg":"STORE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이래서 사진 찍는 건 딱 질색인데 말이야.","JPN":"これだから写真撮影は大嫌いなんだ。","ENG":"This is why I said I didn't want to do a photoshoot.","TWN":"就是因為這樣我才很討厭拍照。"},"stage":{"bg":"STORE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"어떠십니까, 초원 씨? 텍티칼 사의 신제품이랍니다.","JPN":"いかがでしょうか、スズキ・ナオさん？　テクティカル社の新製品です。","ENG":"What do you think of it, Miss Chowon? It's Tactical's newest product.","TWN":"初源，這是裝備公司的新產品，你覺得怎麼樣？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"최첨단 전술 장비 제조사라는 이미지에 걸맞게 뛰어난 스펙을 자랑하죠!","JPN":"最先端戦術装備製作会社というイメージにふさわしい優れた性能ですよ！","ENG":"Being the state-of-the-art gear manufacturer, our products also boast outstanding specifications!","TWN":"這間公司擁有最先進的製造技術，擅長製造最尖端的戰術裝備！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"전 세계 태스크포스 업계가 이 광고를 주목하고 있을 겁니다. 한 말씀 남겨 주시죠!","JPN":"世界中のタスクフォース業界がこの宣伝を見ていると思います。一言お願いします！","ENG":"TASKFORCEs around the globe will be watching this ad. A word, if you will?","TWN":"全世界的特遣勢力都在關注這個廣告，請你說句話吧！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"훌륭한 장비네요. 보험사에서 특히 좋아하겠어요.","JPN":"素晴らしい装備ですね。特に保険会社に喜ばれると思います。","ENG":"This gear is excellent. I'm sure the insurance companies would especially love it.","TWN":"是很出色的裝備，保險公司應該會很喜歡。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"직설적으로 말씀드리면, 겉멋 든 장비보단 구식이라도 신뢰도가 높은 쪽이 낫다는 뜻이에요.","JPN":"ストレートに言いますと、見た目だけの装備より、旧式であっても信頼性の高い装備の方がいいということです。","ENG":"In other words, it's better to have reliable gear, even if it's older than those flashy ones.","TWN":"說直接一點就是，雖然是舊款，但還是比那些中看不中用的裝備好，至少是可信賴的公司生產的。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"슈가 브래드에서 만든 마카롱이 세상에서 가장 맛있는 것처럼~!","JPN":"シュガーブランドが作ったマカロンが世界一美味しいといった感じで～！","ENG":"Imagine that macarons made by Sugar Bread are the best in the world!","TWN":"好像糖果公司生產的馬卡龍是世界上最好吃的馬卡龍，差不多這種感覺～！"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 그럼 찍겠습니다.","JPN":"じゃあ、撮りますよ。","ENG":"Okay, action!","TWN":"好，正式開拍囉。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"한쪽에서는 못 죽여서 안달인데 다른 한쪽에서는 스폰서 광고 모델을 맡겨?","JPN":"私たちを殺したがってる連中がいる一方で、広告モデルを頼んでくるスポンサーがいるなんてな。","ENG":"One side is out to kill us, but the other wants us to be advertising models for our sponsors?","TWN":"一邊是恨不得想趕快除掉我們，另一邊卻找我們當贊助商的廣告模特兒？"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우리가 우승까지 하면 꼴이 꽤 볼 만하겠구만.","JPN":"優勝したらどんな顔をするか見物だね。","ENG":"It'll be really something if we actually win this thing.","TWN":"要是我們最後真的奪冠，那就精彩囉。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헥─! 헥─!","JPN":"ひー、ひー！","ENG":"*Huff–!* *Huff–!*","TWN":"呼—！呼—！"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"하루에 광고 촬영만 5개! 이래서는 훈련할 시간도 없겠어요!","JPN":"今日だけで広告撮影が五つも！　これじゃ訓練もできません！","ENG":"We've done 5 commercials in one day! I don't know if we even have time to train!","TWN":"我一天之內就拍了5個廣告！這樣下去都沒時間訓練了啦！"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헙!? 지금 훈련량이 부족하다는 뜻은 아니에요, 펠리세트!","JPN":"はっ！？　今のは訓練量が足りないという意味ではありませんよ、フェリセット！","ENG":"Oops?! I didn't mean that the training we do now is not enough, Félicette!","TWN":"呃？！費莉塞特，我不是指訓練量不夠的意思喔！"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"전 아무 말도 안 했는데요.","JPN":"私は何も言ってません。","ENG":"I didn't say anything.","TWN":"我又沒說什麼。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"광고 촬영도 선수 활동의 일환이에요.","JPN":"広告撮影も選手活動の一環です。","ENG":"Shooting commercials is a part of being a Gauntlet player.","TWN":"拍攝廣告也是選手工作的一環。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이건 그만큼 우리가 유명해졌다는 뜻이니까.","JPN":"それだけ私たちが有名になったということですから。","ENG":"It also means that we're famous.","TWN":"這就表示我們紅了。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"광고 좀 받았다고 우쭐대긴. 입에 묻은 마카롱 가루나 닦으셔.","JPN":"広告にちょっと出たからって調子に乗っちゃって。とりあえず口元についたマカロンから拭きなよ。","ENG":"Don't be so cocky just because we did some commercials. How about wiping the macaron dust off your lips first?","TWN":"拍了個廣告就得意忘形，先你把嘴角的馬卡龍渣渣擦乾淨吧。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"흠흠, 그리고…….","JPN":"ふむふむ、そして……","ENG":"Ahem. And also...","TWN":"咳咳，還有……"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"동시에 결승 진출이 현실로 이루어졌다는 뜻이고요.","JPN":"決勝進出の夢が叶ったということでもあります。","ENG":"It means that we achieved our goal of making it to the finals.","TWN":"這也就表示，我要打進決賽的夢想成真了。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"다들 고마워요. 여기까지 저를 도와주셔서.","JPN":"みんなありがとうございます。ここまで私の力になってくれて。","ENG":"Thanks, everyone. For helping me come this far.","TWN":"謝謝大家一直以來的幫助。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소리에요. 이제 건틀렛 리그 우승은 저희 모두의 꿈인 걸요.","JPN":"何言ってるんですか。もうガントレットリーグ優勝は私たち全員の夢ですよ。","ENG":"What are you talking about? Winning the Gauntlet is all of our dreams now.","TWN":"胡說什麼，現在拿到聖鎧聯賽冠軍可是我們所有人的夢想。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 마지막까지 저희 최선을 다 하는 거예요!","JPN":"だから最後まで全力を尽くすのみです！","ENG":"That's why we're going to do our best until the end!","TWN":"所以我們要努力拚到最後一刻！"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……맞는 말이네요.","JPN":"……そうですね。","ENG":"...You're right.","TWN":"……你說得對。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아, 그리고 지금 와서 훈련 강도를 높일 생각은 없어요.","JPN":"あ、それから、今更訓練の強度を上げるつもりはありません。","ENG":"Oh, and I don't intend on increasing our training intensity, by the way.","TWN":"還有，我不想現在才提高訓練強度。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"결승까지 얼마 남지 않았어요. 두 사람도 컨디션 유지에 신경 써 주세요.","JPN":"決勝まであと少ししかないですし、二人とも調子を崩さないように気を付けてくださいね。","ENG":"The finals are just around the corner, and you two should maintain your best conditions.","TWN":"距離決賽沒剩多少時間，你們二個要留意自己的狀態。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼, 전 대기실에서 잠깐 눈 좀 붙이고 올게요.","JPN":"では、私は楽屋に戻って少し仮眠を取ってきます。","ENG":"Then, I'll be in the waiting room, getting some shuteye.","TWN":"那我先去休息室瞇一下。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트, 어쩐지 분위기가 차분해진 것 같지 않나요?","JPN":"フェリセット、なんだか落ち着いているように見えませんか？","ENG":"Is it just me or has Félicette gotten calmer these days?","TWN":"你不覺得費莉塞特好像變得沒那麼易怒嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"평소였다면…….","JPN":"いつもなら……","ENG":"If it were the usual Félicette, she'd be like...","TWN":"要是平常……"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"노엘! 고작 촬영 몇 개 했다고 헥─! 헥─! 거리면 어떡해요! 운동장 10바퀴 추가에요!","JPN":"ノエル！　何本か撮影しただけでひいひい言うんじゃありません！　グラウンド10周追加！","ENG":"\\"Noelle! How can you be exhausted after shooting a couple of commercials?! I'm adding 10 more laps to your training routine!\\"","TWN":"洛艾兒！才拍幾個廣告就喘成那樣！再給我再跑十圈！"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"……라고 했을 것 같은데.","JPN":"……って言われてたと思うんですけど。","ENG":"...That'd be more like her.","TWN":"……這才是正常的她吧？"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"사춘기 꼬맹이 속을 내가 어떻게 알겠냐.","JPN":"思春期のガキの気持ちなんかわかんないよ。","ENG":"No one knows what goes on inside the mind of an adolescent kid.","TWN":"青春期的小鬼我不懂啦。"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그동안 코치랑 있으면서 쟤도 뭔가 느낀 게 있었나 보지.","JPN":"しばらくコーチといて、何か気持ちに変化があったんじゃないの。","ENG":"Maybe she's realized something while spending time with our coach.","TWN":"可能是這段時間和教練一起相處，她有感受到什麼吧？"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런가……?","JPN":"そうですかね……？","ENG":"Is that it...?","TWN":"是喔……？"},"stage":{"bg":"STREET_SPRING","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"남의 대기실 앞에서 뭐하는 거예요?","JPN":"人の楽屋の前で何しているんですか？","ENG":"What are you doing in front of my waiting room?","TWN":"你在我們休息室前做什麼？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"정탐이라도 하러 왔어요? 오지만디아스?","JPN":"密偵でもしに来たんですか？　オジマンディアス？","ENG":"Come to snoop around, Ozymandias?","TWN":"你是來打探敵情的嗎？奧茲曼迪亞斯？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 뭐 그렇다고 할까?","JPN":"ふふ、そうね。そういうことにしておこうかしら。","ENG":"Fu fuu. Maybe.","TWN":"呵呵，算是吧？"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"상대의 전력을 분석하는 건 생각보다 중요한 일이거든.","JPN":"相手の戦力を分析するのは、案外大事なのよ。","ENG":"Analyzing your opponents is more important than you might think.","TWN":"分析對手的戰力比想像中還來得重要呢。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"오늘은 보자마자 소리지르면서 달려들지는 않네?","JPN":"今日はいきなり叫びながら襲い掛かってきたりしないのね？","ENG":"I see you're not screaming and running at me like last time.","TWN":"今天怎麼沒有一看到我就大吼大叫撲上來？"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그 사이에 어른스러워졌네. 좋은 후견인을 만나서 그런 걸까나?","JPN":"見ないうちに大人になったわね。良い後見人に出逢えたからかしら？","ENG":"Seems like you've matured a little. Is it because you met yourself a good supporter?","TWN":"這期間變成熟不少呢，是因為遇到好的監護人嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"인터뷰에서 선언했거든요.","JPN":"インタビューで宣言しましたから。","ENG":"I already declared my intentions during my interview.","TWN":"我已經在採訪中宣布，"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러니까…… 당신을 때려 죽이는 건, 모두가 지켜보는 결승전에서예요.","JPN":"だからその通り……あなたを殴り殺すのは、決勝戦のみんなが見ている前でやります。","ENG":"So... beating you up will have to be done in the finals for everyone to see.","TWN":"我……我要在眾所矚目的決賽中殺了你。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아. 그 인터뷰는 나도 봤어.","JPN":"あ、あのインタビューね。","ENG":"Oh. I saw your interview too.","TWN":"喔，我也有看到那個採訪。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"쇼맨십으로는 그럭저럭 나쁘지는 않았는데…….","JPN":"演出としては悪くなかったけど……","ENG":"Your showmanship wasn't too bad...","TWN":"是蠻有節目效果的啦……"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"글쎄? 그런 태도는 너무 식상한 걸?","JPN":"どうかしら？　あの態度は少し陳腐だったんじゃないかしらね？","ENG":"But I dunno. Your attitude was a little dull for my taste.","TWN":"不過，好像有點太老套？"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"기왕 크게 터뜨릴 작정이었으면, 네 부모 건이라도 들먹이지 그랬어.","JPN":"どうせ暴露するんだったら、あなたの両親のことも話せばよかったじゃない。","ENG":"If you were going to go big, why didn't you mention your parents in it?","TWN":"既然想大鬧一場，你何不乾脆說出你父母的事。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어차피 너는 네 부모가 결백하다고 믿고 있는 거잖니?","JPN":"どうせあなたは両親の潔白を信じているんでしょう？","ENG":"You believe that they're innocent, don't you?","TWN":"反正你相信你的父母是無辜的不是嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서 나를 쓰러트리고 그 무죄를 증명하고 싶은 거고.","JPN":"だから私を倒して無罪を証明したい。そうよね？","ENG":"And that's why you want to defeat me and prove they're not guilty to the whole world.","TWN":"所以你才想打敗我證明你父母的清白。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"전혀요. 바보 같은 착각 마세요.","JPN":"いいえ。馬鹿馬鹿しい勘違いはやめてください。","ENG":"Not at all. Don't be stupid.","TWN":"根本不是這樣，你少自以為是。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"바람난 엄마나, 책임감 없이 나 혼자 두고 죽어버린 아빠 같은 건 아무래도 좋아.","JPN":"浮気したママだとか、無責任に私一人を残して死んだパパなんてどうでもいいです。","ENG":"I don't really care about my cheating mother or my irresponsible father who killed himself and left me all alone.","TWN":"無論是出軌的媽媽，還是不負責任丟下我一個人死去的爸爸，我都無所謂。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저는 제 인생을 망친 인간들에게 대가를 치르게 하고 싶을 뿐이에요.","JPN":"私はただ、私の人生をめちゃくちゃにした奴らに復讐したいだけです。","ENG":"All I want is for those who ruined my life to pay for what they did.","TWN":"我只是想讓毀掉我人生的人付出代價而已。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러니까 기대하세요. 당신은 그 인간들 대표거든요.","JPN":"だから楽しみにしていてください。あなたはその代表格ですから。","ENG":"So, I hope you look forward to it as well. Because you represent all of them.","TWN":"所以你敬請期待吧，你就是那些人的代表。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……역시.","JPN":"……やっぱり。","ENG":"...Just as I thought.","TWN":"……果然。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"처음 봤을 때부터 네가 꽤 마음에 들었어, 루이즈 로랑생.","JPN":"最初見た時からあなたには一目置いていたの、ルイーズ・ローランサン。","ENG":"I knew I liked you from the first time we met, Louisé Laurencin.","TWN":"打從我第一眼看到你就蠻喜歡你的，露易絲·羅蘭桑。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"너 같은 예술가 성향을 가진 녀석들은 어떤 일이 있어도 포기하지 않아.","JPN":"あなたのような芸術家タイプの人間は、どんなことがあっても諦めることがない。","ENG":"People with artistic tendencies, like you, never give up.","TWN":"像你這種偏藝術家性格的傢伙，無論發生什麼事都不會放棄。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아무리 방해하고, 짓밟아도 마지막까지 꺾이지 않고 독기를 머금지.","JPN":"どんなに妨害して、踏みにじっても最後まで折れずに牙を向けてくる。","ENG":"Others may try to stop you or stomp on you, but you endure it and never break.","TWN":"不管怎麼妨礙你、怎麼踐踏你，你都會帶著一股狠勁，直到最後一刻也不放棄。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"바로 지금처럼.","JPN":"今みたいにな。","ENG":"Just like right now.","TWN":"就像現在這樣。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서…… 무너뜨릴 보람이 있는 거야.","JPN":"だからこそ……潰し甲斐がある。","ENG":"That's also why... I'll be relishing the moment I destroy you.","TWN":"所以……才有打敗的意義。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"마치 몇 십년을 바라보고 공들여서 빚는 최고급 와인처럼 말이야.","JPN":"何十年も熟成させて作る最高級ワインのようなものよ。","ENG":"Much like how the best wine takes decades to mature.","TWN":"就好像投入幾十年的心力釀成的最高級紅酒，"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"오랜 기다림 끝에 그 마개를 따고 맛과 향을 음미하는 건, 꽤나 각별한 경험이지.","JPN":"待ちに待ったその日、栓を抜いて味と香りを吟味するのはすごく格別な経験だもの。","ENG":"It's a unique experience to enjoy its aroma and taste after the long wait.","TWN":"經過漫長的等待後，打開蓋子品嘗味道，是一種非常特別的體驗。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제정신이 아니네요.","JPN":"狂っていますね。","ENG":"You must be out of your mind.","TWN":"你真是有毛病。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아, 그러고보니 뉴스에서도 나왔죠? 요즘 약도 한다면서요?","JPN":"ああ、そういえば最近はクスリもやっているってニュースに出ていましたね？","ENG":"Oh, I saw you were on the news. You're doing drugs these days?","TWN":"對吼，新聞好像也報導過，說你最近有吸毒？"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐, 그 정도야 나 정도 되는 카운터에겐 불량식품 같은 거거든.","JPN":"まぁ、そんなの私ほどのカウンターになれば、駄菓子をたしなむ程度にしかならないわ。","ENG":"Well, you can't really call them drugs when you're a Counter like me.","TWN":"對我這種水準的制裁者而言，那根本不是毒品，而是垃圾食物。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"중독의 위험성 같은 건, 너희 같은 평범한 인간이나 신경 쓸 일이지.","JPN":"中毒の危険性なんて、あなたのような平凡な人間が心配する類のものよ。","ENG":"Addiction is only something that ordinary people, like you, worry about.","TWN":"吸毒會危害人體這種事，是像你們這種普通人才需要擔心。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그래요? 다른 사람들도 그렇게 생각할까요?","JPN":"ふうん？　果たして他のみんなもそう思うでしょうか？","ENG":"Is that so? You think the public will feel the same way?","TWN":"是嗎？其他人也是這麼想的嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"약물 중독자 챔피언이 평범한 인간에게 뒈지면, 반응이 어떨지 궁금하네요.","JPN":"薬物中毒者のチャンピオンが平凡な人間に負けたら、どんな反響があるか楽しみですね。","ENG":"It'll be fun to see their reaction when an ordinary person defeats a junkie champion.","TWN":"癮君子冠軍如果栽到普通人的手裡，我很好奇大家的反應會如何。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그 잘난 낯짝이 얼마나 흉하게 일그러질지도.","JPN":"その偉そうな面が、どれほど醜く歪むかも。","ENG":"How that smug face of yours will be hideously distorted.","TWN":"還有，你那副囂張的嘴臉又會變得多難看。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래. 어디 한 번 기어올라와 봐, 루이즈. 정상에서 기다리고 있을 테니까.","JPN":"いいわ。這い上がってきてみなさい、ルイーズ。頂上で待っているわ。","ENG":"Yeah. Let's see you try, Louisé. I'll be waiting for you at the top.","TWN":"很好，你努力往上爬吧，露易絲。我會在山頂等你。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하지만 트래시토킹은 아직 더 배워야겠다. 강한 부정은 긍정이야.","JPN":"でも、トラッシュトークはもう少し磨いた方がよさそうね。強い否定は肯定になっちゃうわよ。","ENG":"But you should work on your trash-talking skills. A strong denial just means affirmation, you know?","TWN":"不過，損人的話還是要多學學。強烈的否定就是肯定。"},"stage":{"bg":"CORRIDOR_05","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하아, 하아……!","JPN":"はあ、はあ……！","ENG":"*Huff...* *Huff...*","TWN":"呼呼，呼呼……！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아직…… 아직 모르고 있는 눈치야. 비장의 수단은 들키지 않았어.","JPN":"まだ……まだ気づかれていない様子だった。切り札はまだバレていない。","ENG":"She... She still doesn't know. She doesn't know about my ace up my sleeve.","TWN":"她……好像還沒發現，沒發現我的絕招。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러니까 이걸로…….","JPN":"だから、これで……","ENG":"With this...","TWN":"我一定要用這個……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이걸로 반드시 오지만디아스를…….","JPN":"必ずこれでオジマンディアスを……","ENG":"I'll be finally able to...","TWN":"把奧茲曼迪亞斯給……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시니어를 만나러 가신 분이 제 동의도 없이, 현지에서 직원들을 고용한 것도 모자라서…….","JPN":"シニアとの交渉に出かけて行ったはずが、私に何の相談もせずに現地で社員を採用したばかりか……","ENG":"You said you were going to meet the Senior of Charade. But not only did you go hire new employees, and without asking me first, by the way...","TWN":"明明是去見Senior的，結果竟然沒經過我的同意，就在當地雇用員工……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"회사 명의로, 건틀렛 리그에 나가 결승전까지 올라가셨다고요.","JPN":"会社名義で、ガントレットリーグに出場し、決勝戦まで進出。","ENG":"You also used the company name to enter in the Gauntlet League and made it to the finals.","TWN":"接著還用公司的名義參加聖鎧聯賽，然後還進入決賽？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"참 축하할 일이죠. 좋아하는 사람들이 어찌나 많은지 익명의 협박 메일들이 회사로 쏟아져 들어오더군요.","JPN":"大変おめでたいことですね。応援してくださる方々がたくさんいらっしゃるようで、会社宛てに脅迫メールが山ほど来ていますよ。","ENG":"Well, this is great news. So much so that people are congratulating us by sending piles and piles of anonymous mail threats.","TWN":"真是可喜可賀呢，應該很多人喜歡你們吧？匿名的恐嚇信如雪片般飛來呢。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서? 회사차원에서 축하라도 해드릴까요?","JPN":"それで？　会社をあげてお祝いでもすればよろしいのでしょうか？","ENG":"So? Would you like a congratulations from the company?","TWN":"所以呢？我要站在公司的立場恭喜你嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아쉽게도 본사가 파괴돼서 플랜카드는 못 걸겠지만.","JPN":"大変残念ですが本社が崩壊しておりますので、垂れ幕は無理そうですね。","ENG":"It's a shame that we can't put up a banner due to our main office getting destroyed.","TWN":"只可惜總公司已經變得跟廢墟一樣，無法掛上祝賀布條。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 너무 그러지 말게, 부사장.","JPN":"はは、あんまりそう責め立てるな、副社長。","ENG":"Ha ha, don't be so hard on me, Vice President.","TWN":"哈哈，不要這樣嘛，副總。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네도 어느정도 내 사정은 파악하고 있었을 텐데?","JPN":"君もある程度は事情を知っているではないか？","ENG":"I'm sure you already knew what kind of situation I was in.","TWN":"你應該也多少知道我的情況吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 부탁한 조사는 어떻게 되었지?","JPN":"それより、頼んでおいた調査の件はどうだったね？","ENG":"Aside from that, how is the investigation that I requested going?","TWN":"不過，我拜託你調查的事有結果嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후우…… 뭐, 좋습니다.","JPN":"ふう……まぁ、いいでしょう。","ENG":"*Sigh...* Well, all right.","TWN":"呼……就這樣吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 어느 쪽부터 들으시겠습니까?","JPN":"それでは、どちらからお聞きになりたいですか？","ENG":"So, which one would you like to hear first?","TWN":"你想先聽哪一個？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"스완에 관하여.","JPN":"スワンについて。","ENG":"About Swan.","TWN":"先聽聽史旺的吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"라이카에 관하여.","JPN":"ライカについて。","ENG":"About Laika.","TWN":"先聽聽萊卡的吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"잘 들었네.","JPN":"ご苦労だった。","ENG":"That will be all.","TWN":"我明白了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"말씀하신 신비주의 여배우에 대해서는 그다지 유익한 정보는 없군요.","JPN":"お話いただいた神秘主義の女優に関してはこれといった情報がありませんでした。","ENG":"There was not much useful information about the mysterious actress you mentioned.","TWN":"你說的那個神秘女演員，沒什麼值得報告的。"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니. 오히려 너무 밝혀진 게 없어서 수상할 정도입니다.","JPN":"というより、むしろ情報がなさすぎて怪しいぐらいです。","ENG":"Essentially, nothing is known about her, which makes it even more suspicious.","TWN":"不，應該是說乾淨到很可疑。"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"매년 영화제를 휩쓸 정도면 파파라치가 붙을 법도 한데, 사생활 쪽에선 빈틈이 없어요.","JPN":"毎年映画祭を総なめにしているぐらいですから、パパラッチが追っていてもおかしくないのですが、プライベートは一切漏れていません。","ENG":"She must have paparazzi on her tail with all the awards she receives from the film festivals every year, but still nothing is known about her private life.","TWN":"她每年都從電影節抱回獎項，照理說狗仔應該會盯上她吧？但她的私生活卻從未曝光。"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"필모그래피도 살펴봤습니다만, 제 취향이 아니라는 것 빼곤 이상한 점은 없었습니다.","JPN":"出演作品もざっと見てみましたが、私とは好みが合わないということ以外、おかしな点はありませんでした。","ENG":"I even took a look at her filmography. But all I could find out was that her movies were not to my taste.","TWN":"我還看了她過去拍過的影片，但除了她長得不討我喜歡，其他並沒有可疑之處。"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 평단과 대중의 평가가 항상 일치하리라는 법은 없으니까.","JPN":"まぁ、評論界と大衆の評価は必ずしも一致するわけではないからな。","ENG":"Well, there's no law that says the public and critics' opinions should always match.","TWN":"嗯嗯，評審和大眾的口味向來都是分歧的。"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 라이카라는 직원이 말한 우주 탐사 결과에 관해서는 다소 수확이 있었습니다만…….","JPN":"そのライカという社員が話していたという宇宙探査の結果については多少の収穫がありましたが……","ENG":"I was able to get some information about the space expedition Laika mentioned...","TWN":"有關那個叫萊卡的職員說的宇宙探索，是有點收穫……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"탐사대원은 공식적으로는 탐사를 마친 뒤 대기권으로 돌입 중 전원 사망했다고 합니다.","JPN":"公式的な発表によると、探査隊員は探査終了後、大気圏に突入する過程で全員死亡したそうです。","ENG":"However, the official report states that all expedition members died while returning to the atmosphere.","TWN":"具探索隊員對外的說法是，在完成探索後進入大氣層時就已經全隊死亡。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리실패 이후 우주 방면의 감시 자원들은 복구되지 않았으니까요.","JPN":"管理失敗以降、宇宙方面の監視資源は復旧されていませんから、詳細は不明です。","ENG":"Since the space surveillance resources have not been restored after the Administration Failure.","TWN":"管理失敗以後，宇宙方面的監視資源是無法恢復的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대신, 탐사 목표는 달의 뒷면이었다고 하더군요. 양철 깡통이라도 만나러 간 걸까요?","JPN":"その代わり、探査目標が月の裏面であったことはわかりました。ブリキ缶にでも会いに行ったのでしょうか？","ENG":"Instead, I have learned that the objective of the expedition was to find the dark side of the moon. Perhaps they were trying to meet with the junk metal?","TWN":"不過，聽說探索的目標是月球的背面，難道是去見鐵罐嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네도 여전히 악감정이 남아 있나 보군.","JPN":"君もまだ彼女への嫌悪感が残っているようだな。","ENG":"I see you are still holding a grudge against her.","TWN":"看來你對她很有敵意。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"침식체 주제에 신 흉내나 냈으니까요.","JPN":"侵食体の分際で神のように振舞っていましたから。","ENG":"Because she is nothing but a C.O. that pretended to be a god.","TWN":"誰叫她明明是侵蝕體，還敢裝作自己是神。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쨌거나 그 곳이라면, 현재로선 <color=#ffd34c>세피라</color>에 접촉할 가능성이 가장 높은 지점이겠죠.","JPN":"とにかくあそこなら、現時点では最も高確率で<color=#ffd34c>セフィラ</color>に接触できる場所ではありますね。","ENG":"Anyway, seeing where they were headed, it is somewhere they are most likely to reach <color=#ffd34c>Sephira</color>.","TWN":"總之如果是那個地方，以現在而言，算是最有可能接觸到<color=#ffd34c>巢穴</color>的地方吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"북방합의체가 그것과 접촉해서 뭔가 할 수 있다고는 믿기 어렵습니다만.","JPN":"北方合意体がそれと接触したところで何かができるとは思えませんが。","ENG":"Though it is hard to believe that the Northern Union could do anything if it came into contact with that.","TWN":"不過我想北方和議會就算和她接觸也無法做什麼吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럴 방법을 찾았다면?","JPN":"方法を見つけていたとしたら？","ENG":"What if they found a way?","TWN":"但如果有找到方法呢？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아직은 추측일세. 그렇게 쏘아보지 말게나.","JPN":"まだ推測に過ぎないんだ。そんなに睨まないでくれ。","ENG":"I am just assuming. Please don't glare at me like that.","TWN":"這只是推測而已，不要瞪我。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"출장 나가자마자, 주목을 많이 끌고 계신 것 같더군요.","JPN":"出張に出て間もないのに、大変注目を集められているようですね。","ENG":"It seems that you have garnered quite a bit of attention as soon as you went on your business trip.","TWN":"老闆一出差好像就備受矚目呢。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"좋은 쪽으로든, 나쁜 쪽으로든 말이죠.","JPN":"良くも悪くもです。","ENG":"Both in good and bad ways, that is.","TWN":"先不論是好是壞，"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"모쪼록 조심하시기 바랍니다.","JPN":"とにかく、くれぐれもお気を付けください。","ENG":"Please do be careful.","TWN":"總之，你小心點吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아, 그리고 한 가지 더. 자네가 조사해줬으면 하는 일이 있네.","JPN":"あ、あともう一つ。君に調べてほしいことがある。","ENG":"Oh, there's one more thing that I want to you take a look at.","TWN":"那個，還有一件事，我希望你能幫我調查一下。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"여전히 직원 부리는 게 험하시군요.","JPN":"相変わらず人使いが荒いですね。","ENG":"I see you are still relentless with your employees.","TWN":"你還是很會使喚員工嘛。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"말씀하시죠.","JPN":"何でしょうか。","ENG":"What is it?","TWN":"請說吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"노엘 양에 대해서 다시 한 번 조사해 주게.","JPN":"ノエル君についてもう一度調査してみてくれないか。","ENG":"I want you to do another background search on Noelle.","TWN":"重新幫我調查一下洛艾兒吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};